async def run_tasks(tasks, max_concurrent):
    """Run async tasks with a concurrency limit.

    Accepts a list of async zero-argument callables.  At most
    *max_concurrent* tasks run simultaneously.

    If the run is cancelled (e.g. KeyboardInterrupt/SIGINT via
    *asyncio.run*), tasks that have already started are allowed to
    finish so their cleanup code runs; queued tasks that have not
    started are not started after cancellation begins.

    Parameters
    ----------
    tasks:
        An iterable of async zero-argument callables.
    max_concurrent:
        Maximum number of tasks to run at the same time.
    """
    if max_concurrent <= 0:
        raise ValueError("max_concurrent must be positive")

    it = iter(tasks)
    pending = set()

    # Seed the pool with the first *max_concurrent* tasks.
    for _ in range(max_concurrent):
        try:
            fn = next(it)
        except StopIteration:
            break
        pending.add(asyncio.create_task(fn()))

    cancelled = False
    try:
        while pending:
            done, pending = await asyncio.wait(
                pending, return_when=asyncio.FIRST_COMPLETED
            )

            # Surface exceptions from finished tasks.
            for d in done:
                d.result()

            # Replenish the pool.  If we are in a cancellation state
            # new tasks are NOT started.
            if not cancelled:
                for _ in range(len(done)):
                    try:
                        fn = next(it)
                    except StopIteration:
                        break
                    pending.add(asyncio.create_task(fn()))
    except asyncio.CancelledError:
        cancelled = True
    finally:
        # Wait for already-started tasks to finish their cleanup.
        if pending:
            try:
                await asyncio.wait(pending)
            except asyncio.CancelledError:
                pass
        if cancelled:
            raise
